/// Commands that require async I/O (network calls).
pub enum AsyncCommand {
    // ── Auth ──────────────────────────────────────────────────────────
    Login {
        email: String,
        [REDACTED_CREDENTIAL]
    },

    // ── Upload flow (existing) ────────────────────────────────────────
    FetchUploadTeams,
    UploadSession {
        session_json: serde_json::Value,
        team_id: Option<String>,
        body_url: Option<String>,
    },

    // ── Teams ─────────────────────────────────────────────────────────
    FetchTeams,
    FetchTeamDetail(String),
    FetchMembers(String),
    CreateTeam {
        name: String,
    },
    InviteMember {
        team_id: String,
        email: String,
    },
    RemoveMember {
        team_id: String,
        user_id: String,
    },

    // ── Invitations ───────────────────────────────────────────────────
    FetchInvitations,
    AcceptInvitation(String),
    DeclineInvitation(String),

    // ── Profile / Account ─────────────────────────────────────────────
    FetchProfile,
    ChangePassword {
        current: String,
        new_[REDACTED_CREDENTIAL]
    },
    RegenerateApiKey,

    // ── Server Sessions ───────────────────────────────────────────────
    #[allow(dead_code)]
    FetchServerSessions(SessionListQuery),

    // ── Delete ────────────────────────────────────────────────────────
    DeleteSession { session_id: String },
}

/// Results returned by async commands.
pub enum CommandResult {
    // Auth
    Login(Result<(String, String), String>), // (api_key, nickname)

    // Upload flow
    UploadTeams(Result<Vec<TeamInfo>, String>),
    UploadDone(Result<String, String>),

    // Teams
    Teams(Result<Vec<TeamResponse>, String>),
    TeamDetail(Result<TeamDetailResponse, String>),
    Members(Result<Vec<MemberResponse>, String>),

    // Invitations
    Invitations(Result<Vec<InvitationResponse>, String>),

    // Profile / Account
    Profile(Result<UserSettingsResponse, String>),
    ApiKey(Result<RegenerateKeyResponse, String>),

    // Server Sessions
    ServerSessions(Result<SessionListResponse, String>),

    // Generic OK (team create, invite, remove, password change, accept/decline)
    GenericOk(Result<String, String>),

    // Delete
    DeleteSession(Result<String, String>), // Ok(session_id) or Err(msg)
}

fn make_client(config: &DaemonConfig) -> Result<opensession_api_client::ApiClient, String> {
    let mut client =
        opensession_api_client::ApiClient::new(&config.server.url, Duration::from_secs(15))
            .map_err(|e| format!("Failed to create HTTP client: {e}"))?;
    client.set_auth(config.server.api_key.clone());
    Ok(client)
}

pub async fn execute(cmd: AsyncCommand, config: &DaemonConfig) -> CommandResult {
    match cmd {
        // ── Login ─────────────────────────────────────────────────────
        AsyncCommand::Login { email, password } => {
            let result = async {
                let mut client = opensession_api_client::ApiClient::new(
                    &config.server.url,
                    Duration::from_secs(10),
                )
                .map_err(|e| format!("Failed to create HTTP client: {e}"))?;

                let tokens = client
                    .login(&LoginRequest { email, password })
                    .await
                    .map_err(|e| format!("{e}"))?;

                client.set_auth(tokens.access_token);
                let user = client.me().await.map_err(|e| format!("{e}"))?;
                Ok((user.api_key, user.nickname))
            }
            .await;
            CommandResult::Login(result)
        }

        // ── Upload flow ───────────────────────────────────────────────
        AsyncCommand::FetchUploadTeams => {
            let result = async {
                let client = make_client(config)?;
                let list = client.list_teams().await.map_err(|e| format!("{e}"))?;

                let mut teams = vec![TeamInfo {
                    id: String::new(),
                    name: "Personal (Public)".to_string(),
                    is_personal: true,
                }];
                for t in list.teams {
                    teams.push(TeamInfo {
                        id: t.id,
                        name: t.name,
                        is_personal: false,
                    });
                }
                Ok(teams)
            }
            .await;
            CommandResult::UploadTeams(result)
        }

        AsyncCommand::UploadSession {
            session_json,
            team_id,
            body_url,
        } => {
            let result = async {
                let client = make_client(config)?;
                let session: opensession_core::trace::Session =
                    serde_json::from_value(session_json).map_err(|e| format!("parse: {e}"))?;
                let resp = client
                    .upload_session(&UploadRequest {
                        session,
                        team_id,
                        body_url,
                        linked_session_ids: None,
                        git_remote: None,
                        git_branch: None,
                        git_commit: None,
                        git_repo_name: None,
                        pr_number: None,
                        pr_url: None,
                    })
                    .await
                    .map_err(|e| format!("{e}"))?;
                Ok(resp.url)
            }
            .await;
            CommandResult::UploadDone(result)
        }

        // ── Teams ─────────────────────────────────────────────────────
        AsyncCommand::FetchTeams => {
            let result = async {
                let client = make_client(config)?;
                let list = client.list_teams().await.map_err(|e| format!("{e}"))?;
                Ok(list.teams)
            }
            .await;
            CommandResult::Teams(result)
        }

        AsyncCommand::FetchTeamDetail(id) => {
            let result = async {
                let client = make_client(config)?;
                client.get_team(&id).await.map_err(|e| format!("{e}"))
            }
            .await;
            CommandResult::TeamDetail(result)
        }

        AsyncCommand::FetchMembers(team_id) => {
            let result = async {
                let client = make_client(config)?;
                let list = client
                    .list_members(&team_id)
                    .await
                    .map_err(|e| format!("{e}"))?;
                Ok(list.members)
            }
            .await;
            CommandResult::Members(result)
        }

        AsyncCommand::CreateTeam { name } => {
            let result = async {
                let client = make_client(config)?;
                let resp = client
                    .create_team(&CreateTeamRequest {
                        name: name.clone(),
                        description: None,
                        is_public: Some(false),
                    })
                    .await
                    .map_err(|e| format!("{e}"))?;
                Ok(format!("Team '{}' created", resp.name))
            }
            .await;
            CommandResult::GenericOk(result)
        }

        AsyncCommand::InviteMember { team_id, email } => {
            let result = async {
                let client = make_client(config)?;
                client
                    .invite_member(
                        &team_id,
                        &InviteRequest {
                            email: Some(email.clone()),
                            oauth_provider: None,
                            oauth_provider_username: None,
                            role: None,
                        },
                    )
                    .await
                    .map_err(|e| format!("{e}"))?;
                Ok(format!("Invitation sent to {email}"))
            }
            .await;
            CommandResult::GenericOk(result)
        }

        AsyncCommand::RemoveMember { team_id, user_id } => {
            let result = async {
                let client = make_client(config)?;
                client
                    .remove_member(&team_id, &user_id)
                    .await
                    .map_err(|e| format!("{e}"))?;
                Ok("Member removed".to_string())
            }
            .await;
            CommandResult::GenericOk(result)
        }

        // ── Invitations ───────────────────────────────────────────────
        AsyncCommand::FetchInvitations => {
            let result = async {
                let client = make_client(config)?;
                let list = client
                    .list_invitations()
                    .await
                    .map_err(|e| format!("{e}"))?;
                Ok(list.invitations)
            }
            .await;
            CommandResult::Invitations(result)
        }

        AsyncCommand::AcceptInvitation(id) => {
            let result = async {
                let client = make_client(config)?;
                let resp = client
                    .accept_invitation(&id)
                    .await
                    .map_err(|e| format!("{e}"))?;
                Ok(format!("Joined team (role: {})", resp.role))
            }
            .await;
            CommandResult::GenericOk(result)
        }

        AsyncCommand::DeclineInvitation(id) => {
            let result = async {
                let client = make_client(config)?;
                client
                    .decline_invitation(&id)
                    .await
                    .map_err(|e| format!("{e}"))?;
                Ok("Invitation declined".to_string())
            }
            .await;
            CommandResult::GenericOk(result)
        }

        // ── Profile / Account ─────────────────────────────────────────
        AsyncCommand::FetchProfile => {
            let result = async {
                let client = make_client(config)?;
                client.me().await.map_err(|e| format!("{e}"))
            }
            .await;
            CommandResult::Profile(result)
        }

        AsyncCommand::ChangePassword {
            current,
            new_password,
        } => {
            let result = async {
                let client = make_client(config)?;
                client
                    .change_password(&ChangePasswordRequest {
                        current_[REDACTED_CREDENTIAL]
                        new_password,
                    })
                    .await
                    .map_err(|e| format!("{e}"))?;
                Ok("Password changed".to_string())
            }
            .await;
            CommandResult::GenericOk(result)
        }

        AsyncCommand::RegenerateApiKey => {
            let result = async {
                let client = make_client(config)?;
                client.regenerate_key().await.map_err(|e| format!("{e}"))
            }
            .await;
            CommandResult::ApiKey(result)
        }

        // ── Delete ─────────────────────────────────────────────────────
        AsyncCommand::DeleteSession { session_id } => {
            let result = async {
                let client = make_client(config)?;
                client
                    .delete_session(&session_id)
                    .await
                    .map_err(|e| format!("{e}"))?;
                Ok(session_id)
            }
            .await;
            CommandResult::DeleteSession(result)
        }

        // ── Server Sessions ───────────────────────────────────────────
        AsyncCommand::FetchServerSessions(query) => {
            let result = async {
                let client = make_client(config)?;
                client
                    .list_sessions(&query)
                    .await
                    .map_err(|e| format!("{e}"))
            }
            .await;
            CommandResult::ServerSessions(result)
        }
    }
}

use crate::app::{
    App, ConnectionContext, DetailViewMode, EventFilter, FlashLevel, ListLayout, ServerStatus,
    SettingsSection, TaskViewMode, UploadPhase, View, ViewMode,
};
use crate::theme::Theme;
use crate::views::{
    help, invitations, modal, session_detail, session_list, settings, setup, tab_bar, team_detail,
    teams,
};
use ratatui::prelude::*;
use ratatui::widgets::{Clear, Paragraph};

pub fn render(frame: &mut Frame, app: &mut App) {
    // Setup is always full-screen
    if matches!(app.view, View::Setup) {
        setup::render(frame, app, frame.area());
        // Modal overlay
        if let Some(ref m) = app.modal {
            modal::render(frame, m, &app.edit_buffer);
        }
        return;
    }

    let [tab_area, header_area, body_area, footer_area] = Layout::vertical([
        Constraint::Length(1),
        Constraint::Length(3),
        Constraint::Fill(1),
        Constraint::Length(1),
    ])
    .areas(frame.area());

    // Tab bar
    tab_bar::render(
        frame,
        &app.active_tab,
        &app.view,
        tab_area,
        app.invitations.len(),
    );

    // Header
    render_header(frame, app, header_area);

    // Body
    match app.view {
        View::SessionList => session_list::render(frame, app, body_area),
        View::SessionDetail => session_detail::render(frame, app, body_area),
        View::Settings => settings::render(frame, app, body_area),
        View::Teams => teams::render(frame, app, body_area),
        View::TeamDetail => team_detail::render(frame, app, body_area),
        View::Invitations => invitations::render(frame, app, body_area),
        View::Help => {} // rendered as overlay below
        View::Setup => {} // handled above
    }

    // Footer
    render_footer(frame, app, footer_area);

    // Upload popup overlay (legacy)
    if app.upload_popup.is_some() {
        render_upload_popup(frame, app);
    }

    // Help overlay
    if matches!(app.view, View::Help) {
        help::render(frame, frame.area());
    }

    // Modal overlay
    if let Some(ref m) = app.modal {
        modal::render(frame, m, &app.edit_buffer);
    }
}

fn render_header(frame: &mut Frame, app: &App, area: Rect) {
    match app.view {
        View::SessionList => {
            let block = Theme::block();
            let inner = block.inner(area);
            frame.render_widget(block, area);

            // Left side: title + connection badge + view mode + session count
            let count = app.session_count();
            let mode_label = match &app.view_mode {
                ViewMode::Local => "Local".to_string(),
                ViewMode::Team(t) => format!("Team: {t}"),
                ViewMode::Repo(r) => format!("Repo: {r}"),
            };

            // Connection context badge
            let (badge_text, badge_fg, badge_bg) = match &app.connection_ctx {
                ConnectionContext::Local => {
                    ("LOCAL".to_string(), Color::Black, Theme::BADGE_LOCAL)
                }
                ConnectionContext::Docker { .. } => {
                    ("DOCKER".to_string(), Color::Black, Theme::BADGE_DOCKER)
                }
                ConnectionContext::CloudPersonal => (
                    "PERSONAL".to_string(),
                    Color::Black,
                    Theme::BADGE_PERSONAL,
                ),
                ConnectionContext::CloudTeam { team_name } => (
                    format!("TEAM: {team_name}"),
                    Color::Black,
                    Theme::BADGE_TEAM,
                ),
            };

            let session_count_span = if app.loading_sessions {
                Span::styled(
                    "Loading...",
                    Style::new().fg(Theme::ACCENT_YELLOW).italic(),
                )
            } else {
                Span::styled(
                    format!("{} sessions", count),
                    Style::new().fg(Theme::TEXT_SECONDARY),
                )
            };

            let mut left_spans = vec![
                Span::styled(
                    " opensession ",
                    Style::new().fg(Theme::ACCENT_ORANGE).bold(),
                ),
                Span::styled(" ", Style::new()),
                Span::styled(
                    format!(" {} ", badge_text),
                    Style::new().fg(badge_fg).bg(badge_bg).bold(),
                ),
                Span::styled("  ", Style::new()),
                Span::styled(mode_label, Style::new().fg(Theme::ACCENT_BLUE)),
                Span::styled("  ", Style::new()),
                session_count_span,
            ];

            if !app.search_query.is_empty() {
                left_spans.push(Span::styled(
                    format!("  (filtered from {})", app.sessions.len()),
                    Style::new().fg(Color::DarkGray),
                ));
            }

            // Tool filter indicator
            if let Some(ref tool) = app.tool_filter {
                left_spans.push(Span::styled("  ", Style::new()));
                left_spans.push(Span::styled(
                    format!(" tool:{tool} "),
                    Style::new()
                        .fg(Color::Black)
                        .bg(Color::Magenta)
                        .bold(),
                ));
            }

            // Page indicator
            if app.total_pages() > 1 {
                left_spans.push(Span::styled(
                    format!("  Page {}/{}", app.page + 1, app.total_pages()),
                    Style::new().fg(Theme::TEXT_SECONDARY),
                ));
            }

            // Startup status indicators
            let status = &app.startup_status;
            if status.repos_detected > 0 {
                left_spans.push(Span::styled("  ", Style::new().fg(Color::DarkGray)));
                left_spans.push(Span::styled(
                    format!("{} repos", status.repos_detected),
                    Style::new().fg(Theme::TEXT_MUTED),
                ));
            }

            let left_line = Line::from(left_spans);
            let p = Paragraph::new(left_line).alignment(Alignment::Left);
            frame.render_widget(p, inner);

            // Right side: daemon status + server status
            let mut right_spans = Vec::new();

            // Daemon status
            if let Some(pid) = status.daemon_pid {
                right_spans.push(Span::styled(
                    format!("daemon:{pid} "),
                    Style::new().fg(Theme::ACCENT_GREEN),
                ));
            } else if status.config_exists {
                right_spans.push(Span::styled(
                    "daemon:off ",
                    Style::new().fg(Theme::TEXT_SECONDARY),
                ));
            }

            // Server status
            if let Some(ref info) = app.server_info {
                right_spans.extend(build_server_status_spans(info));
            }

            if !right_spans.is_empty() {
                let right_line = Line::from(right_spans);
                let p_right = Paragraph::new(right_line).alignment(Alignment::Right);
                frame.render_widget(p_right, inner);
            }
        }
        View::SessionDetail => {
            let filters = [
                ("1:All", EventFilter::All),
                ("2:Msgs", EventFilter::Messages),
                ("3:Tools", EventFilter::ToolCalls),
                ("4:Think", EventFilter::Thinking),
                ("5:Files", EventFilter::FileOps),
                ("6:Shell", EventFilter::Shell),
            ];

            let mut spans = vec![Span::styled(" ", Style::new())];
            for (label, filter) in &filters {
                let active = app.event_filters.contains(filter);
                let style = if active {
                    Style::new()
                        .fg(Color::Black)
                        .bg(Theme::ACCENT_BLUE)
                        .bold()
                } else {
                    Style::new().fg(Theme::TEXT_MUTED)
                };
                spans.push(Span::styled(format!(" {} ", label), style));
                spans.push(Span::styled(" ", Style::new()));
            }

            // Task view mode indicator (only when session has sub-agents)
            if app.session_has_sub_agents() {
                spans.push(Span::styled(" │ ", Style::new().fg(Theme::GUTTER)));
                let (task_label, task_style) = match app.task_view_mode {
                    TaskViewMode::Summary => (
                        "Tasks:Summary",
                        Style::new()
                            .fg(Color::Black)
                            .bg(Theme::ROLE_TASK)
                            .bold(),
                    ),
                    TaskViewMode::Detail => {
                        ("Tasks:Detail", Style::new().fg(Theme::ROLE_TASK))
                    }
                };
                spans.push(Span::styled(format!(" {} ", task_label), task_style));
            }

            // Collapse indicator
            if app.collapse_consecutive {
                spans.push(Span::styled(" ", Style::new()));
                spans.push(Span::styled(
                    " c:on ",
                    Style::new()
                        .fg(Color::Black)
                        .bg(Theme::ACCENT_GREEN)
                        .bold(),
                ));
            }

            let line = Line::from(spans);
            let p = Paragraph::new(line).block(Theme::block());
            frame.render_widget(p, area);
        }
        View::Teams | View::TeamDetail => {
            let block = Theme::block();
            let inner = block.inner(area);
            frame.render_widget(block, area);

            let title = if matches!(app.view, View::TeamDetail) {
                app.team_detail
                    .as_ref()
                    .map(|d| format!(" Team: {} ", d.team.name))
                    .unwrap_or_else(|| " Team Detail ".to_string())
            } else {
                " Teams ".to_string()
            };

            let spans = vec![Span::styled(
                title,
                Style::new().fg(Theme::ACCENT_ORANGE).bold(),
            )];
