//! Session query builders.

use sea_query::{Alias, Asterisk, Expr, Func, JoinType, Order, Query, SqliteQueryBuilder};

use super::tables::{SessionLinks, Sessions, Users};
use crate::SessionListQuery;

pub type Built = (String, sea_query::Values);

/// Result of building a paginated session list query.
pub struct BuiltSessionListQuery {
    pub count_query: Built,
    pub select_query: Built,
    pub page: u32,
    pub per_page: u32,
}

// ── Helpers ────────────────────────────────────────────────────────────────

/// Add the standard session columns (+ nickname from users join) to a SELECT.
/// Column order must match `session_from_row()` positional mappers.
fn session_columns(q: &mut sea_query::SelectStatement) -> &mut sea_query::SelectStatement {
    q.column((Sessions::Table, Sessions::Id))
        .column((Sessions::Table, Sessions::UserId))
        .column((Users::Table, Users::Nickname))
        .column((Sessions::Table, Sessions::TeamId))
        .column((Sessions::Table, Sessions::Tool))
        .column((Sessions::Table, Sessions::AgentProvider))
        .column((Sessions::Table, Sessions::AgentModel))
        .column((Sessions::Table, Sessions::Title))
        .column((Sessions::Table, Sessions::Description))
        .column((Sessions::Table, Sessions::Tags))
        .column((Sessions::Table, Sessions::CreatedAt))
        .column((Sessions::Table, Sessions::UploadedAt))
        .column((Sessions::Table, Sessions::MessageCount))
        .column((Sessions::Table, Sessions::TaskCount))
        .column((Sessions::Table, Sessions::EventCount))
        .column((Sessions::Table, Sessions::DurationSeconds))
        .column((Sessions::Table, Sessions::TotalInputTokens))
        .column((Sessions::Table, Sessions::TotalOutputTokens))
        .column((Sessions::Table, Sessions::GitRemote))
        .column((Sessions::Table, Sessions::GitBranch))
        .column((Sessions::Table, Sessions::GitCommit))
        .column((Sessions::Table, Sessions::GitRepoName))
        .column((Sessions::Table, Sessions::PrNumber))
        .column((Sessions::Table, Sessions::PrUrl))
        .column((Sessions::Table, Sessions::WorkingDirectory))
        .column((Sessions::Table, Sessions::FilesModified))
        .column((Sessions::Table, Sessions::FilesRead))
        .column((Sessions::Table, Sessions::HasErrors))
}

/// Base SELECT for session listings (with users JOIN).
fn session_select() -> sea_query::SelectStatement {
    let mut q = Query::select().to_owned();
    session_columns(&mut q);
    q.from(Sessions::Table)
        .left_join(
            Users::Table,
            Expr::col((Sessions::Table, Sessions::UserId)).equals((Users::Table, Users::Id)),
        )
        .to_owned()
}

// ── Queries ────────────────────────────────────────────────────────────────

/// Parameters for inserting a session.
pub struct InsertParams<'a> {
    pub id: &'a str,
    pub user_id: &'a str,
    pub team_id: &'a str,
    pub tool: &'a str,
    pub agent_provider: &'a str,
    pub agent_model: &'a str,
    pub title: &'a str,
    pub description: &'a str,
    pub tags: &'a str,
    pub created_at: &'a str,
    pub message_count: i64,
    pub task_count: i64,
    pub event_count: i64,
    pub duration_seconds: i64,
    pub total_input_tokens: i64,
    pub total_output_tokens: i64,
    pub body_storage_key: &'a str,
    pub body_url: Option<&'a str>,
    pub git_remote: Option<&'a str>,
    pub git_branch: Option<&'a str>,
    pub git_commit: Option<&'a str>,
    pub git_repo_name: Option<&'a str>,
    pub pr_number: Option<i64>,
    pub pr_url: Option<&'a str>,
    pub working_directory: Option<&'a str>,
    pub files_modified: Option<&'a str>,
    pub files_read: Option<&'a str>,
    pub has_errors: bool,
}

/// INSERT a new session.
pub fn insert(p: &InsertParams<'_>) -> Built {
    Query::insert()
        .into_table(Sessions::Table)
        .columns([
            Sessions::Id,
            Sessions::UserId,
            Sessions::TeamId,
            Sessions::Tool,
            Sessions::AgentProvider,
            Sessions::AgentModel,
            Sessions::Title,
            Sessions::Description,
            Sessions::Tags,
            Sessions::CreatedAt,
            Sessions::MessageCount,
            Sessions::TaskCount,
            Sessions::EventCount,
            Sessions::DurationSeconds,
            Sessions::TotalInputTokens,
            Sessions::TotalOutputTokens,
            Sessions::BodyStorageKey,
            Sessions::BodyUrl,
            Sessions::GitRemote,
            Sessions::GitBranch,
            Sessions::GitCommit,
            Sessions::GitRepoName,
            Sessions::PrNumber,
            Sessions::PrUrl,
            Sessions::WorkingDirectory,
            Sessions::FilesModified,
            Sessions::FilesRead,
            Sessions::HasErrors,
        ])
        .values_panic([
            p.id.into(),
            p.user_id.into(),
            p.team_id.into(),
            p.tool.into(),
            p.agent_provider.into(),
            p.agent_model.into(),
            p.title.into(),
            p.description.into(),
            p.tags.into(),
            p.created_at.into(),
            p.message_count.into(),
            p.task_count.into(),
            p.event_count.into(),
            p.duration_seconds.into(),
            p.total_input_tokens.into(),
            p.total_output_tokens.into(),
            p.body_storage_key.into(),
            p.body_url.map(|s| s.to_string()).into(),
            p.git_remote.map(|s| s.to_string()).into(),
            p.git_branch.map(|s| s.to_string()).into(),
            p.git_commit.map(|s| s.to_string()).into(),
            p.git_repo_name.map(|s| s.to_string()).into(),
            p.pr_number.into(),
            p.pr_url.map(|s| s.to_string()).into(),
            p.working_directory.map(|s| s.to_string()).into(),
            p.files_modified.map(|s| s.to_string()).into(),
            p.files_read.map(|s| s.to_string()).into(),
            p.has_errors.into(),
        ])
        .build(SqliteQueryBuilder)
}

/// SELECT a single session by id (with users JOIN).
pub fn get_by_id(id: &str) -> Built {
    session_select()
        .and_where(Expr::col((Sessions::Table, Sessions::Id)).eq(id))
        .build(SqliteQueryBuilder)
}

/// SELECT `body_storage_key, body_url` for a session.
pub fn get_storage_info(id: &str) -> Built {
    Query::select()
        .column(Sessions::BodyStorageKey)
        .column(Sessions::BodyUrl)
        .from(Sessions::Table)
        .and_where(Expr::col(Sessions::Id).eq(id))
        .build(SqliteQueryBuilder)
}

/// Build paginated session list queries with dynamic filters.
pub fn list(q: &SessionListQuery) -> BuiltSessionListQuery {
    let per_page = q.per_page.clamp(1, 100);
    let offset = (q.page.saturating_sub(1)) * per_page;

    // Build shared WHERE conditions
    let mut count_q = Query::select()
        .expr_as(Func::count(Expr::col(Asterisk)), Alias::new("count"))
        .from_as(Sessions::Table, Alias::new("s"))
        .to_owned();

    let mut select_q = Query::select().to_owned();
    // Use table alias "s" for sessions, "u" for users
    select_q
        .column((Alias::new("s"), Sessions::Id))
        .column((Alias::new("s"), Sessions::UserId))
        .column((Alias::new("u"), Users::Nickname))
        .column((Alias::new("s"), Sessions::TeamId))
        .column((Alias::new("s"), Sessions::Tool))
        .column((Alias::new("s"), Sessions::AgentProvider))
        .column((Alias::new("s"), Sessions::AgentModel))
        .column((Alias::new("s"), Sessions::Title))
        .column((Alias::new("s"), Sessions::Description))
        .column((Alias::new("s"), Sessions::Tags))
        .column((Alias::new("s"), Sessions::CreatedAt))
        .column((Alias::new("s"), Sessions::UploadedAt))
        .column((Alias::new("s"), Sessions::MessageCount))
        .column((Alias::new("s"), Sessions::TaskCount))
        .column((Alias::new("s"), Sessions::EventCount))
        .column((Alias::new("s"), Sessions::DurationSeconds))
        .column((Alias::new("s"), Sessions::TotalInputTokens))
        .column((Alias::new("s"), Sessions::TotalOutputTokens))
        .column((Alias::new("s"), Sessions::GitRemote))
        .column((Alias::new("s"), Sessions::GitBranch))
        .column((Alias::new("s"), Sessions::GitCommit))
        .column((Alias::new("s"), Sessions::GitRepoName))
        .column((Alias::new("s"), Sessions::PrNumber))
        .column((Alias::new("s"), Sessions::PrUrl))
        .column((Alias::new("s"), Sessions::WorkingDirectory))
        .column((Alias::new("s"), Sessions::FilesModified))
        .column((Alias::new("s"), Sessions::FilesRead))
        .column((Alias::new("s"), Sessions::HasErrors))
        .from_as(Sessions::Table, Alias::new("s"))
        .join_as(
            JoinType::LeftJoin,
            Users::Table,
            Alias::new("u"),
            Expr::col((Alias::new("u"), Users::Id)).equals((Alias::new("s"), Sessions::UserId)),
        );

    // Base filter: non-empty sessions
    let base_cond = Expr::col((Alias::new("s"), Sessions::EventCount))
        .gt(0)
        .or(Expr::col((Alias::new("s"), Sessions::MessageCount)).gt(0));
    count_q.and_where(base_cond.clone());
    select_q.and_where(base_cond);

    if let Some(ref tool) = q.tool {
        let cond = Expr::col((Alias::new("s"), Sessions::Tool)).eq(tool.as_str());
        count_q.and_where(cond.clone());
        select_q.and_where(cond);
    }

    if let Some(ref team_id) = q.team_id {
        let cond = Expr::col((Alias::new("s"), Sessions::TeamId)).eq(team_id.as_str());
        count_q.and_where(cond.clone());
        select_q.and_where(cond);
    }

    if let Some(ref search) = q.search {
        let like = format!("%{search}%");
        let cond = Expr::col((Alias::new("s"), Sessions::Title))
            .like(&like)
            .or(Expr::col((Alias::new("s"), Sessions::Description)).like(&like))
            .or(Expr::col((Alias::new("s"), Sessions::Tags)).like(&like));
        count_q.and_where(cond.clone());
        select_q.and_where(cond);
    }

    if let Some(ref time_range) = q.time_range {
        let interval = match time_range {
            crate::TimeRange::Hours24 => Some("-1 day"),
            crate::TimeRange::Days7 => Some("-7 days"),
            crate::TimeRange::Days30 => Some("-30 days"),
            crate::TimeRange::All => None,
        };
        if let Some(interval) = interval {
            let cond =
                Expr::col((Alias::new("s"), Sessions::CreatedAt)).gte(Expr::cust_with_values::<
                    _,
                    sea_query::Value,
                    _,
                >(
                    "datetime('now', ?)",
                    [interval.into()],
                ));
            count_q.and_where(cond.clone());
            select_q.and_where(cond);
        }
    }

    // Sort
    match q.sort.as_ref().unwrap_or(&crate::SortOrder::Recent) {
        crate::SortOrder::Popular => {
            select_q
                .order_by((Alias::new("s"), Sessions::MessageCount), Order::Desc)
                .order_by((Alias::new("s"), Sessions::CreatedAt), Order::Desc);
        }
        crate::SortOrder::Longest => {
            select_q
                .order_by((Alias::new("s"), Sessions::DurationSeconds), Order::Desc)
                .order_by((Alias::new("s"), Sessions::CreatedAt), Order::Desc);
        }
        crate::SortOrder::Recent => {
            select_q.order_by((Alias::new("s"), Sessions::CreatedAt), Order::Desc);
        }
    }

    select_q.limit(per_page as u64).offset(offset as u64);

    BuiltSessionListQuery {
        count_query: count_q.build(SqliteQueryBuilder),
        select_query: select_q.build(SqliteQueryBuilder),
        page: q.page,
        per_page,
    }
}

/// INSERT a session link.
pub fn insert_link(session_id: &str, linked_session_id: &str, link_type: crate::LinkType) -> Built {
    // INSERT OR IGNORE
    let sql = "INSERT OR IGNORE INTO \"session_links\" (\"session_id\", \"linked_session_id\", \"link_type\") VALUES (?, ?, ?)".to_string();
    let values = sea_query::Values(vec![
        session_id.into(),
        linked_session_id.into(),
        link_type.as_str().into(),
    ]);
    (sql, values)
}

/// SELECT all links for a session (both directions).
pub fn links_by_session(session_id: &str) -> Built {
    Query::select()
        .column(SessionLinks::SessionId)
        .column(SessionLinks::LinkedSessionId)
        .column(SessionLinks::LinkType)
        .column(SessionLinks::CreatedAt)
        .from(SessionLinks::Table)
        .cond_where(
            sea_query::Cond::any()
                .add(Expr::col(SessionLinks::SessionId).eq(session_id))
                .add(Expr::col(SessionLinks::LinkedSessionId).eq(session_id)),
        )
        .build(SqliteQueryBuilder)
}

/// DELETE a session by id.
pub fn delete(id: &str) -> Built {
    Query::delete()
        .from_table(Sessions::Table)
        .and_where(Expr::col(Sessions::Id).eq(id))
        .build(SqliteQueryBuilder)
}

/// DELETE all links for a session.
pub fn delete_links(session_id: &str) -> Built {
    Query::delete()
        .from_table(SessionLinks::Table)
        .and_where(
            Expr::col(SessionLinks::SessionId)
                .eq(session_id)
                .or(Expr::col(SessionLinks::LinkedSessionId).eq(session_id)),
        )
        .build(SqliteQueryBuilder)
}

/// SELECT session listing for a team (e.g., recent 50 for team detail).
pub fn list_by_team(team_id: &str, limit: u64) -> Built {
    session_select()
        .and_where(Expr::col((Sessions::Table, Sessions::TeamId)).eq(team_id))
        .and_where(
            Expr::col((Sessions::Table, Sessions::EventCount))
                .gt(0)
                .or(Expr::col((Sessions::Table, Sessions::MessageCount)).gt(0)),
        )
        .order_by((Sessions::Table, Sessions::CreatedAt), Order::Desc)
        .limit(limit)
        .build(SqliteQueryBuilder)
}

/// SELECT for sync pull: keyset pagination by (uploaded_at, id).
pub fn sync_pull(
    team_id: &str,
    cursor_uploaded_at: Option<&str>,
    cursor_session_id: Option<&str>,
    limit: u64,
) -> Built {
    let mut q = session_select()
        .and_where(Expr::col((Sessions::Table, Sessions::TeamId)).eq(team_id))
        .to_owned();

    match (cursor_uploaded_at, cursor_session_id) {
        (Some(at), Some(sid)) => {
            // Keyset pagination: (uploaded_at, id) > (cursor_at, cursor_id)
            q.and_where(
                Expr::tuple([
                    Expr::col((Sessions::Table, Sessions::UploadedAt)).into(),
                    Expr::col((Sessions::Table, Sessions::Id)).into(),
                ])
                .gt(Expr::tuple([Expr::value(at), Expr::value(sid)])),
            );
        }
        (Some(at), None) => {
            // Legacy cursor: just uploaded_at > cursor
            q.and_where(Expr::col((Sessions::Table, Sessions::UploadedAt)).gt(at));
        }
        _ => {}
    }

    q.order_by((Sessions::Table, Sessions::UploadedAt), Order::Asc)
        .order_by((Sessions::Table, Sessions::Id), Order::Asc)
        .limit(limit)
        .build(SqliteQueryBuilder)
}

use base64::{engine::general_purpose::STANDARD, Engine};
use serde::Deserialize;

pub struct PlatformApiStorage {
    client: reqwest::blocking::Client,
    [REDACTED_CREDENTIAL]
}

enum Platform {
    GitHub { owner: String, repo: String },
    GitLab { project_path: String },
}

impl PlatformApiStorage {
    pub fn new([REDACTED_CREDENTIAL] -> Self {
        Self {
            client: reqwest::blocking::Client::new(),
            token,
        }
    }

    /// Upload a session file to the `opensession` branch via platform API.
    /// Returns the raw content URL on success.
    pub fn store(
        &self,
        remote_url: &str,
        session_id: &str,
        jsonl: &[u8],
    ) -> Result<String, String> {
        let platform = detect_platform(remote_url)?;
        let rel_path = format!(".opensession/{session_id}.hail.jsonl");

        match &platform {
            Platform::GitHub { owner, repo } => {
                self.github_store(owner, repo, &rel_path, jsonl)?;
            }
            Platform::GitLab { project_path } => {
                self.gitlab_store(project_path, &rel_path, jsonl)?;
            }
        }

        Ok(opensession_git_native::generate_raw_url(
            remote_url, &rel_path,
        ))
    }

    // ── GitHub ───────────────────────────────────────────────────────────

    fn gh_get(&self, url: &str) -> reqwest::blocking::RequestBuilder {
        self.client
            .get(url)
            .header("Authorization", format!("Bearer {}", self.token))
            .header("User-Agent", "opensession")
    }

    fn gh_post(&self, url: &str) -> reqwest::blocking::RequestBuilder {
        self.client
            .post(url)
            .header("Authorization", format!("Bearer {}", self.token))
            .header("User-Agent", "opensession")
    }

    fn gh_put(&self, url: &str) -> reqwest::blocking::RequestBuilder {
        self.client
            .put(url)
            .header("Authorization", format!("Bearer {}", self.token))
            .header("User-Agent", "opensession")
    }

    fn github_store(
        &self,
        owner: &str,
        repo: &str,
        path: &str,
        content: &[u8],
    ) -> Result<(), String> {
        let base = format!("https://api.github.com/repos/{owner}/{repo}");

        let branch_exists = self
            .gh_get(&format!("{base}/branches/opensession"))
            .send()
            .map(|r| r.status().is_success())
            .unwrap_or(false);

        if !branch_exists {
            self.github_create_orphan(&base, path, content)?;
            return Ok(());
        }

        // Branch exists — check if file already exists (need sha for update)
        let file_sha = self.github_file_sha(&base, path);
        self.github_put_contents(&base, path, content, file_sha.as_deref())
    }

    fn github_create_orphan(&self, base: &str, path: &str, content: &[u8]) -> Result<(), String> {
        // 1. Create blob
        let blob: ShaResponse = self
            .gh_post(&format!("{base}/git/blobs"))
            .json(&serde_json::json!({
                "content": STANDARD.encode(content),
                "encoding": "base64"
            }))
            .send()
            .map_err(|e| format!("blob: {e}"))?
            .json()
            .map_err(|e| format!("blob parse: {e}"))?;

        // 2. Create tree
        let tree: ShaResponse = self
            .gh_post(&format!("{base}/git/trees"))
            .json(&serde_json::json!({
                "tree": [{
                    "path": path,
                    "mode": "100644",
                    "type": "blob",
                    "sha": blob.sha
                }]
            }))
            .send()
            .map_err(|e| format!("tree: {e}"))?
            .json()
            .map_err(|e| format!("tree parse: {e}"))?;

        // 3. Create commit (no parents → orphan)
        let commit: ShaResponse = self
            .gh_post(&format!("{base}/git/commits"))
            .json(&serde_json::json!({
                "message": "Add session",
                "tree": tree.sha,
                "parents": []
            }))
            .send()
            .map_err(|e| format!("commit: {e}"))?
            .json()
            .map_err(|e| format!("commit parse: {e}"))?;

        // 4. Create ref
        let resp = self
            .gh_post(&format!("{base}/git/refs"))
            .json(&serde_json::json!({
                "ref": "refs/heads/opensession",
                "sha": commit.sha
            }))
            .send()
            .map_err(|e| format!("ref: {e}"))?;

        if !resp.status().is_success() {
            let body = resp.text().unwrap_or_default();
            return Err(format!("ref create failed: {body}"));
        }
        Ok(())
    }

    fn github_file_sha(&self, base: &str, path: &str) -> Option<String> {
        self.gh_get(&format!("{base}/contents/{path}?ref=opensession"))
            .send()
            .ok()
            .filter(|r| r.status().is_success())
            .and_then(|r| r.json::<ShaResponse>().ok())
            .map(|f| f.sha)
    }

    fn github_put_contents(
        &self,
        base: &str,
        path: &str,
        content: &[u8],
        sha: Option<&str>,
    ) -> Result<(), String> {
        let mut body = serde_json::json!({
            "message": "Update session",
            "content": STANDARD.encode(content),
            "branch": "opensession"
        });
        if let Some(sha) = sha {
            body["sha"] = serde_json::Value::String(sha.to_string());
        }

        let resp = self
            .gh_put(&format!("{base}/contents/{path}"))
            .json(&body)
            .send()
            .map_err(|e| format!("upload: {e}"))?;

        if !resp.status().is_success() {
            let status = resp.status();
            let body = resp.text().unwrap_or_default();
            return Err(format!("GitHub upload failed ({status}): {body}"));
        }
        Ok(())
    }

    // ── GitLab ──────────────────────────────────────────────────────────

    fn gl_get(&self, url: &str) -> reqwest::blocking::RequestBuilder {
        self.client.get(url).header("PRIVATE-TOKEN", &self.token)
    }

    fn gl_post(&self, url: &str) -> reqwest::blocking::RequestBuilder {
        self.client.post(url).header("PRIVATE-TOKEN", &self.token)
    }

    fn gl_put(&self, url: &str) -> reqwest::blocking::RequestBuilder {
        self.client.put(url).header("PRIVATE-TOKEN", &self.token)
    }

    fn gitlab_store(&self, project_path: &str, path: &str, content: &[u8]) -> Result<(), String> {
        // GitLab API requires URL-encoded project path
        let encoded_project = project_path.replace('/', "%2F");
        let base = format!("https://gitlab.com/api/v4/projects/{encoded_project}");

        let branch_exists = self
            .gl_get(&format!("{base}/repository/branches/opensession"))
            .send()
            .map(|r| r.status().is_success())
            .unwrap_or(false);

        if !branch_exists {
            return self.gitlab_create_branch_with_file(&base, path, content);
        }

        // Branch exists — check if file exists
        let encoded_path = path.replace('/', "%2F");
        let file_exists = self
            .gl_get(&format!(
                "{base}/repository/files/{encoded_path}?ref=opensession"
            ))
            .send()
            .map(|r| r.status().is_success())
            .unwrap_or(false);

        let file_body = serde_json::json!({
            "branch": "opensession",
            "commit_message": if file_exists { "Update session" } else { "Add session" },
            "content": STANDARD.encode(content),
            "encoding": "base64"
        });

        let url = format!("{base}/repository/files/{encoded_path}");
        let resp = if file_exists {
            self.gl_put(&url).json(&file_body).send()
        } else {
            self.gl_post(&url).json(&file_body).send()
        };

        let resp = resp.map_err(|e| format!("GitLab file op: {e}"))?;
        if !resp.status().is_success() {
            let status = resp.status();
            let body = resp.text().unwrap_or_default();
            return Err(format!("GitLab file op failed ({status}): {body}"));
        }
        Ok(())
    }

    fn gitlab_create_branch_with_file(
        &self,
        base: &str,
        path: &str,
        content: &[u8],
    ) -> Result<(), String> {
        let body = serde_json::json!({
            "branch": "opensession",
            "start_branch": "main",
            "commit_message": "Add session",
            "actions": [{
                "action": "create",
                "file_path": path,
                "content": STANDARD.encode(content),
                "encoding": "base64"
            }]
        });

        let resp = self
            .gl_post(&format!("{base}/repository/commits"))
            .json(&body)
            .send()
            .map_err(|e| format!("GitLab commit: {e}"))?;

        if resp.status().is_success() {
            return Ok(());
        }

        // Fallback: try "master" as start_branch
        let body_master = serde_json::json!({
            "branch": "opensession",
            "start_branch": "master",
            "commit_message": "Add session",
            "actions": [{
                "action": "create",
                "file_path": path,
                "content": STANDARD.encode(content),
                "encoding": "base64"
            }]
        });

        let resp2 = self
            .gl_post(&format!("{base}/repository/commits"))
            .json(&body_master)
            .send()
            .map_err(|e| format!("GitLab commit (master): {e}"))?;

        if !resp2.status().is_success() {
            let status = resp2.status();
            let body = resp2.text().unwrap_or_default();
            return Err(format!("GitLab branch creation failed ({status}): {body}"));
        }
        Ok(())
    }
}

fn detect_platform(remote_url: &str) -> Result<Platform, String> {
    let normalized = remote_url
        .trim()
        .trim_end_matches(".git")
        .replace("git@github.com:", "https://github.com/")
        .replace("git@gitlab.com:", "https://gitlab.com/");

    if normalized.contains("github.com") {
        let path = normalized.trim_start_matches("https://github.com/");
        let (owner, repo) = path
            .split_once('/')
            .ok_or_else(|| format!("Cannot parse GitHub owner/repo from: {remote_url}"))?;
        Ok(Platform::GitHub {
            owner: owner.to_string(),
            repo: repo.to_string(),
        })
    } else if normalized.contains("gitlab.com") {
        let path = normalized.trim_start_matches("https://gitlab.com/");
        if path.is_empty() || !path.contains('/') {
            return Err(format!(
                "Cannot parse GitLab project path from: {remote_url}"
            ));
        }
        Ok(Platform::GitLab {
            project_path: path.to_string(),
        })
    } else {
        Err(format!("Unsupported git platform: {remote_url}"))
    }
}

