### 7. **allow_public Determination** (`app.rs` lines 2389-2422)

Checks per-repo `.opensession/config.toml`:

```rust
pub fn selected_session_allows_public(&self) -> bool {
    let session = self.selected_session()?;
    let cwd = session.context.attributes.get("cwd")?;
    let repo_root = find_repo_root(cwd)?;

    // Read allow_public from config.toml or config.local.toml
    for name in &["config.toml", "config.local.toml"] {
        let path = repo_root.join(".opensession").join(name);
        if let Ok(content) = std::fs::read_to_string(&path) {
            if let Ok(val) = toml::from_str::<toml::Value>(&content) {
                if let Some(false) = val.get("allow_public").and_then(|v| v.as_bool()) {
                    return false;  // Repo disallows personal uploads
                }
            }
        }
    }
    true  // Default: allow public
}
```

